Component({
  properties: {
    textContent: {
      type: String,
      value: '',
      observer(newVal) {
        const regRN = /\r|\n|\\s/g
        let str = `<p>${newVal}</p>`
        str = str.replace(regRN, '<br/>')
        this.setData({
          text: str
        })
      }
    }
  },
  data: {
    text: ''
  }
})
